import { OpenModal } from "../../../components/DialogHRM";
import { CalendarPicker_Cmpt } from "../../../components";
import { parseDate } from "../../../stores/Utils";

const CalendarModalPicker = CalendarPicker_Cmpt();

const DateCalComponent  = ({ init, label, updDate }) => {

    const confirmCalendar = (v) => {
        updDate(v.initDate + 800);
    }

    const openCalendar = () => {
        let modal_data = {};
        modal_data["zIndex"] = 950;
        modal_data["height"] = "80vh";
        // data['observeResize']=true;
        modal_data["props"] = { minHeight: "1vh", overlay: true };
        modal_data["content"] = 
            <CalendarModalPicker onConfirm={confirmCalendar} init={init}/>
        
        OpenModal(modal_data);
    }
    return(
        <div>
            
            <p className="label">
                {label || "Fecha"}
            </p>
            <div className="date2Upd" onClick={openCalendar}>
                { init ? parseDate(init): parseDate((new Date()).getTime())}
            </div>
        </div>
    )

}

export default DateCalComponent;